import React, { useState } from 'react';
import { useMutation, useQueryClient } from '@tanstack/react-query';
import { useAuth } from '../context/AuthContext';
import { authAPI } from '../services/api';
import toast from 'react-hot-toast';
import {
  User, Lock, Shield, Key,
  Eye, EyeOff, Save, CheckCircle, Info,
} from 'lucide-react';

const TABS = [
  { id: 'profile',  icon: User,   label: 'Profile'  },
  { id: 'password', icon: Lock,   label: 'Password' },
  { id: 'security', icon: Shield, label: 'Security' },
  { id: 'api',      icon: Key,    label: 'API Info' },
];

const inp = {
  width: '100%', padding: '10px 12px', border: '1px solid #e2e8f0',
  borderRadius: '8px', fontSize: '14px', outline: 'none',
  boxSizing: 'border-box', background: 'white', color: '#0f172a',
};

const SectionCard = ({ title, desc, children }) => (
  <div style={{
    background: 'white', borderRadius: '14px', border: '1px solid #f1f5f9',
    boxShadow: '0 1px 3px rgba(0,0,0,0.04)', overflow: 'hidden', marginBottom: '20px',
  }}>
    <div style={{ padding: '18px 24px', borderBottom: '1px solid #f8fafc' }}>
      <h3 style={{ fontSize: '15px', fontWeight: 700, color: '#0f172a' }}>{title}</h3>
      {desc && <p style={{ fontSize: '13px', color: '#64748b', marginTop: '3px' }}>{desc}</p>}
    </div>
    <div style={{ padding: '24px' }}>{children}</div>
  </div>
);

const Label = ({ children, hint }) => (
  <div style={{ marginBottom: '16px' }}>
    <label style={{ display: 'block', fontSize: '13px', fontWeight: 600, color: '#374151', marginBottom: '6px' }}>
      {children}
    </label>
    {hint && <p style={{ fontSize: '12px', color: '#94a3b8', marginTop: '4px' }}>{hint}</p>}
  </div>
);

// ── Profile Tab ───────────────────────────────────────────────
function ProfileTab({ user }) {
  const { } = useAuth();
  const [name, setName] = useState(user?.name || '');
  const [saved, setSaved] = useState(false);

  const mutation = useMutation({
    mutationFn: () => authAPI.updateProfile({ name }),
    onSuccess: (res) => {
      // Update localStorage
      const stored = JSON.parse(localStorage.getItem('sms_user') || '{}');
      localStorage.setItem('sms_user', JSON.stringify({ ...stored, name: res.data.data.name }));
      setSaved(true);
      setTimeout(() => setSaved(false), 3000);
      toast.success('Profile updated!');
    },
    onError: (e) => toast.error(e.response?.data?.message || 'Update failed'),
  });

  return (
    <form onSubmit={e => { e.preventDefault(); mutation.mutate(); }}>
      <SectionCard title="Personal Information" desc="Your display name and account details">
        {/* Avatar */}
        <div style={{ display: 'flex', gap: '18px', alignItems: 'center', marginBottom: '24px', padding: '16px', background: '#f8fafc', borderRadius: '12px' }}>
          <div style={{
            width: '64px', height: '64px', borderRadius: '50%', flexShrink: 0,
            background: 'linear-gradient(135deg, #6366f1, #8b5cf6)',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            fontSize: '24px', fontWeight: 800, color: 'white',
            boxShadow: '0 4px 14px rgba(99,102,241,0.35)',
          }}>
            {name?.charAt(0).toUpperCase()}
          </div>
          <div>
            <div style={{ fontWeight: 700, fontSize: '16px', color: '#0f172a' }}>{name || user?.name}</div>
            <div style={{ fontSize: '13px', color: '#64748b', marginTop: '2px' }}>{user?.email}</div>
            <span style={{
              display: 'inline-block', marginTop: '6px',
              padding: '2px 10px', borderRadius: '10px', fontSize: '11px', fontWeight: 700,
              background: user?.role === 'admin' ? '#fef3c7' : user?.role === 'manager' ? '#dbeafe' : '#f1f5f9',
              color:      user?.role === 'admin' ? '#92400e' : user?.role === 'manager' ? '#1e40af' : '#475569',
            }}>{user?.role?.toUpperCase()}</span>
          </div>
        </div>

        <div style={{ marginBottom: '16px' }}>
          <label style={{ display: 'block', fontSize: '13px', fontWeight: 600, color: '#374151', marginBottom: '6px' }}>Full Name *</label>
          <input style={inp} value={name} onChange={e => setName(e.target.value)} required placeholder="Your full name" />
        </div>

        <div style={{ marginBottom: '24px' }}>
          <label style={{ display: 'block', fontSize: '13px', fontWeight: 600, color: '#374151', marginBottom: '6px' }}>Email Address</label>
          <input style={{ ...inp, background: '#f8fafc', color: '#94a3b8' }} value={user?.email || ''} disabled />
          <p style={{ fontSize: '12px', color: '#94a3b8', marginTop: '5px' }}>Email cannot be changed. Contact admin if needed.</p>
        </div>

        <button type="submit" disabled={mutation.isPending} style={{
          display: 'inline-flex', alignItems: 'center', gap: '7px', padding: '10px 22px',
          background: saved ? '#22c55e' : 'linear-gradient(135deg, #6366f1, #8b5cf6)',
          border: 'none', borderRadius: '8px', color: 'white',
          fontWeight: 600, fontSize: '14px', cursor: 'pointer', transition: 'background 0.3s',
        }}>
          {saved ? <><CheckCircle size={15} /> Saved!</> : mutation.isPending ? 'Saving...' : <><Save size={15} /> Save Changes</>}
        </button>
      </SectionCard>
    </form>
  );
}

// ── Password Tab ──────────────────────────────────────────────
function PasswordTab() {
  const [form, setForm] = useState({ currentPassword: '', newPassword: '', confirmPassword: '' });
  const [showCurrent, setShowCurrent] = useState(false);
  const [showNew, setShowNew]         = useState(false);

  const getStrength = (pw) => {
    if (!pw) return null;
    let score = 0;
    if (pw.length >= 8)          score++;
    if (/[A-Z]/.test(pw))        score++;
    if (/[0-9]/.test(pw))        score++;
    if (/[^a-zA-Z0-9]/.test(pw)) score++;
    const levels = [
      null,
      { label: 'Weak',   color: '#ef4444' },
      { label: 'Fair',   color: '#f59e0b' },
      { label: 'Good',   color: '#22c55e' },
      { label: 'Strong', color: '#16a34a' },
    ];
    return { score, ...levels[score] };
  };

  const strength = getStrength(form.newPassword);

  const mutation = useMutation({
    mutationFn: () => authAPI.changePassword({
      currentPassword: form.currentPassword,
      newPassword: form.newPassword,
    }),
    onSuccess: () => {
      setForm({ currentPassword: '', newPassword: '', confirmPassword: '' });
      toast.success('Password changed successfully!');
    },
    onError: (e) => toast.error(e.response?.data?.message || 'Failed to change password'),
  });

  const handleSubmit = (e) => {
    e.preventDefault();
    if (form.newPassword !== form.confirmPassword) return toast.error('Passwords do not match');
    if (form.newPassword.length < 8) return toast.error('Minimum 8 characters required');
    mutation.mutate();
  };

  return (
    <form onSubmit={handleSubmit}>
      <SectionCard title="Change Password" desc="Use a strong password — mix of letters, numbers and symbols">
        <div style={{ marginBottom: '16px' }}>
          <label style={{ display: 'block', fontSize: '13px', fontWeight: 600, color: '#374151', marginBottom: '6px' }}>Current Password</label>
          <div style={{ position: 'relative' }}>
            <input type={showCurrent ? 'text' : 'password'} style={inp} value={form.currentPassword}
              onChange={e => setForm({ ...form, currentPassword: e.target.value })} required placeholder="Enter current password" />
            <button type="button" onClick={() => setShowCurrent(!showCurrent)} style={{ position: 'absolute', right: '12px', top: '50%', transform: 'translateY(-50%)', background: 'none', border: 'none', cursor: 'pointer', color: '#94a3b8' }}>
              {showCurrent ? <EyeOff size={16} /> : <Eye size={16} />}
            </button>
          </div>
        </div>

        <div style={{ marginBottom: '16px' }}>
          <label style={{ display: 'block', fontSize: '13px', fontWeight: 600, color: '#374151', marginBottom: '6px' }}>New Password</label>
          <div style={{ position: 'relative' }}>
            <input type={showNew ? 'text' : 'password'} style={inp} value={form.newPassword}
              onChange={e => setForm({ ...form, newPassword: e.target.value })} required placeholder="Min 8 characters" />
            <button type="button" onClick={() => setShowNew(!showNew)} style={{ position: 'absolute', right: '12px', top: '50%', transform: 'translateY(-50%)', background: 'none', border: 'none', cursor: 'pointer', color: '#94a3b8' }}>
              {showNew ? <EyeOff size={16} /> : <Eye size={16} />}
            </button>
          </div>
          {strength && (
            <div style={{ marginTop: '8px' }}>
              <div style={{ display: 'flex', gap: '4px', marginBottom: '4px' }}>
                {[1,2,3,4].map(i => (
                  <div key={i} style={{ flex:1, height:'4px', borderRadius:'2px', background: i <= strength.score ? strength.color : '#f1f5f9', transition:'background 0.3s' }} />
                ))}
              </div>
              <span style={{ fontSize: '12px', color: strength.color, fontWeight: 600 }}>{strength.label}</span>
            </div>
          )}
        </div>

        <div style={{ marginBottom: '24px' }}>
          <label style={{ display: 'block', fontSize: '13px', fontWeight: 600, color: '#374151', marginBottom: '6px' }}>Confirm New Password</label>
          <input type="password" style={{ ...inp, borderColor: form.confirmPassword && form.newPassword !== form.confirmPassword ? '#ef4444' : '#e2e8f0' }}
            value={form.confirmPassword} onChange={e => setForm({ ...form, confirmPassword: e.target.value })} required placeholder="Repeat new password" />
          {form.confirmPassword && form.newPassword !== form.confirmPassword && (
            <p style={{ fontSize: '12px', color: '#ef4444', marginTop: '5px' }}>Passwords do not match</p>
          )}
        </div>

        <button type="submit" disabled={mutation.isPending} style={{ display: 'inline-flex', alignItems: 'center', gap: '7px', padding: '10px 22px', background: 'linear-gradient(135deg, #6366f1, #8b5cf6)', border: 'none', borderRadius: '8px', color: 'white', fontWeight: 600, fontSize: '14px', cursor: 'pointer' }}>
          <Lock size={15} /> {mutation.isPending ? 'Changing...' : 'Change Password'}
        </button>
      </SectionCard>
    </form>
  );
}

// ── Security Tab ──────────────────────────────────────────────
function SecurityTab({ user }) {
  const checks = [
    { icon: '🔐', title: 'Strong Password',    desc: 'Use 8+ characters with letters, numbers and symbols' },
    { icon: '🌐', title: 'HTTPS Only',          desc: 'All data transmitted over encrypted SSL connection'  },
    { icon: '⏱️', title: 'JWT Token Expiry',    desc: 'Sessions automatically expire after 7 days'          },
    { icon: '🛡️', title: 'Rate Limiting',       desc: 'API is protected against brute force attacks'        },
    { icon: '📋', title: 'Audit Logging',       desc: 'Every action is logged with IP and timestamp'        },
    { icon: '🔒', title: 'Role-Based Access',   desc: 'Admin/Manager/User permissions enforced on every route' },
  ];
  return (
    <>
      <SectionCard title="Security Checklist" desc="Your account security overview">
        <div style={{ display: 'grid', gap: '8px' }}>
          {checks.map(c => (
            <div key={c.title} style={{ display: 'flex', alignItems: 'center', gap: '14px', padding: '12px 14px', background: '#f8fafc', borderRadius: '10px' }}>
              <span style={{ fontSize: '18px' }}>{c.icon}</span>
              <div style={{ flex: 1 }}>
                <div style={{ fontSize: '13px', fontWeight: 600, color: '#0f172a' }}>{c.title}</div>
                <div style={{ fontSize: '12px', color: '#64748b', marginTop: '1px' }}>{c.desc}</div>
              </div>
              <CheckCircle size={16} color="#22c55e" />
            </div>
          ))}
        </div>
      </SectionCard>

      <SectionCard title="Current Session" desc="Your active login session">
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '14px', background: '#f8fafc', borderRadius: '10px' }}>
          <div>
            <div style={{ fontSize: '13px', fontWeight: 600, color: '#0f172a' }}>This browser</div>
            <div style={{ fontSize: '12px', color: '#64748b', marginTop: '2px' }}>{user?.email} · {new Date().toLocaleDateString('en-US', { weekday:'short', month:'short', day:'numeric' })}</div>
          </div>
          <span style={{ padding: '3px 10px', background: '#dcfce7', color: '#16a34a', borderRadius: '10px', fontSize: '12px', fontWeight: 600 }}>Active</span>
        </div>
        <p style={{ fontSize: '12px', color: '#94a3b8', marginTop: '10px', display: 'flex', alignItems: 'center', gap: '5px' }}>
          <Info size={11} /> Changing your password will invalidate all other sessions.
        </p>
      </SectionCard>
    </>
  );
}

// ── API Info Tab ──────────────────────────────────────────────
function ApiTab() {
  const [showToken, setShowToken] = useState(false);
  const token  = localStorage.getItem('sms_token') || '';
  const masked = token ? token.slice(0, 24) + '••••••••' + token.slice(-8) : '';

  const copy = (text) => { navigator.clipboard.writeText(text); toast.success('Copied!'); };

  const endpoints = [
    { m:'POST', p:'/api/auth/login',               d:'Get JWT token'        },
    { m:'GET',  p:'/api/contacts',                 d:'List contacts'        },
    { m:'POST', p:'/api/contacts',                 d:'Add contact'          },
    { m:'POST', p:'/api/contacts/import',          d:'Import CSV/Excel'     },
    { m:'GET',  p:'/api/contacts/lists',           d:'Contact lists'        },
    { m:'GET',  p:'/api/campaigns',                d:'List campaigns'       },
    { m:'POST', p:'/api/campaigns',                d:'Create campaign'      },
    { m:'POST', p:'/api/campaigns/:id/launch',     d:'Launch campaign'      },
    { m:'GET',  p:'/api/templates',                d:'List templates'       },
    { m:'GET',  p:'/api/messages',                 d:'Messages log'         },
    { m:'GET',  p:'/api/messages/stats',           d:'Message stats'        },
    { m:'GET',  p:'/api/messages/opt-outs',        d:'Opt-out log'          },
    { m:'GET',  p:'/api/analytics/dashboard',      d:'Dashboard data'       },
    { m:'POST', p:'/api/webhooks/twilio/inbound',  d:'Twilio inbound SMS'   },
    { m:'POST', p:'/api/webhooks/twilio/status',   d:'Delivery status'      },
  ];

  const mc = { GET:['#dbeafe','#1e40af'], POST:['#dcfce7','#166534'], PUT:['#fef3c7','#92400e'], DELETE:['#fee2e2','#991b1b'] };

  return (
    <>
      <SectionCard title="Your Bearer Token" desc="Use this to authenticate API requests from external tools">
        <div style={{ background: '#0f172a', borderRadius: '10px', padding: '16px', marginBottom: '14px' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '10px' }}>
            <span style={{ color: '#94a3b8', fontSize: '11px', fontWeight: 700, letterSpacing: '0.05em' }}>BEARER TOKEN</span>
            <div style={{ display: 'flex', gap: '8px' }}>
              <button onClick={() => setShowToken(!showToken)} style={{ background: 'rgba(255,255,255,0.08)', border: 'none', borderRadius: '5px', color: '#94a3b8', cursor: 'pointer', padding: '3px 10px', fontSize: '12px' }}>
                {showToken ? 'Hide' : 'Show'}
              </button>
              <button onClick={() => copy(token)} style={{ background: 'rgba(99,102,241,0.3)', border: 'none', borderRadius: '5px', color: '#a5b4fc', cursor: 'pointer', padding: '3px 10px', fontSize: '12px', fontWeight: 600 }}>
                Copy
              </button>
            </div>
          </div>
          <div style={{ fontFamily: 'monospace', fontSize: '12px', color: '#a5b4fc', wordBreak: 'break-all', lineHeight: 1.7 }}>
            {showToken ? token : masked}
          </div>
        </div>
        <div style={{ background: '#fef9c3', borderRadius: '8px', padding: '10px 14px', fontSize: '12px', color: '#92400e', display: 'flex', gap: '6px', alignItems: 'flex-start' }}>
          <span>⚠️</span><span>Keep this token private. Yeh token kisi ke saath share mat karo.</span>
        </div>
      </SectionCard>

      <SectionCard title="Example Request" desc="How to call the API from your code">
        <div style={{ background: '#0f172a', borderRadius: '10px', padding: '16px', fontSize: '12px', fontFamily: 'monospace', lineHeight: 1.8, color: '#e2e8f0', overflowX: 'auto' }}>
          <div style={{ color: '#94a3b8' }}>{'// JavaScript fetch example'}</div>
          <div><span style={{ color: '#7dd3fc' }}>const</span> res = <span style={{ color: '#7dd3fc' }}>await</span> <span style={{ color: '#86efac' }}>fetch</span>(<span style={{ color: '#fca5a5' }}>'/api/campaigns'</span>, {'{'}</div>
          <div>&nbsp;&nbsp;method: <span style={{ color: '#fca5a5' }}>'GET'</span>,</div>
          <div>&nbsp;&nbsp;headers: {'{'}</div>
          <div>&nbsp;&nbsp;&nbsp;&nbsp;<span style={{ color: '#fca5a5' }}>'Authorization'</span>: <span style={{ color: '#fca5a5' }}>`Bearer ${'${token}'}`</span>,</div>
          <div>&nbsp;&nbsp;{'}'}</div>
          <div>{'}'});</div>
          <div><span style={{ color: '#7dd3fc' }}>const</span> data = <span style={{ color: '#7dd3fc' }}>await</span> res.<span style={{ color: '#86efac' }}>json</span>();</div>
        </div>
      </SectionCard>

      <SectionCard title="All API Endpoints" desc="Complete REST API reference">
        <div style={{ display: 'flex', flexDirection: 'column', gap: '5px' }}>
          {endpoints.map((ep, i) => {
            const [bg, color] = mc[ep.m] || mc.GET;
            return (
              <div key={i} style={{ display: 'flex', alignItems: 'center', gap: '10px', padding: '8px 10px', background: '#f8fafc', borderRadius: '6px' }}>
                <span style={{ padding: '2px 6px', borderRadius: '4px', background: bg, color, fontSize: '10px', fontWeight: 700, width: '40px', textAlign: 'center', flexShrink: 0 }}>{ep.m}</span>
                <span style={{ fontFamily: 'monospace', fontSize: '12px', color: '#374151', flex: 1 }}>{ep.p}</span>
                <span style={{ fontSize: '12px', color: '#94a3b8', whiteSpace: 'nowrap' }}>{ep.d}</span>
              </div>
            );
          })}
        </div>
      </SectionCard>
    </>
  );
}

// ── Main Page ─────────────────────────────────────────────────
export default function SettingsPage() {
  const { user, updateUser } = useAuth();
  const [tab, setTab] = useState('profile');

  const content = { profile: <ProfileTab user={user} />, password: <PasswordTab />, security: <SecurityTab user={user} />, api: <ApiTab /> };

  return (
    <div style={{ padding: '32px', background: '#f8fafc', minHeight: '100vh' }}>
      <div style={{ marginBottom: '28px' }}>
        <h1 style={{ fontSize: '24px', fontWeight: 700, color: '#0f172a' }}>Settings</h1>
        <p style={{ color: '#64748b', marginTop: '4px' }}>Manage your account and preferences</p>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '200px 1fr', gap: '24px', alignItems: 'flex-start' }}>
        <div style={{ background: 'white', borderRadius: '14px', padding: '8px', border: '1px solid #f1f5f9', boxShadow: '0 1px 3px rgba(0,0,0,0.04)' }}>
          {TABS.map(t => {
            const Icon = t.icon;
            const active = tab === t.id;
            return (
              <button key={t.id} onClick={() => setTab(t.id)} style={{
                display: 'flex', alignItems: 'center', gap: '9px', width: '100%',
                padding: '9px 12px', borderRadius: '8px', border: 'none', cursor: 'pointer',
                marginBottom: '2px', textAlign: 'left', fontSize: '13px', transition: 'all 0.15s',
                background: active ? '#eef2ff' : 'transparent', color: active ? '#6366f1' : '#64748b',
                fontWeight: active ? 600 : 400, borderLeft: active ? '3px solid #6366f1' : '3px solid transparent',
              }}>
                <Icon size={15} />{t.label}
              </button>
            );
          })}
        </div>
        <div>{content[tab]}</div>
      </div>
    </div>
  );
}
